import sys

class Solution:
    def findMaximumXOR(self, nums: list[int]) -> int:
        if not nums:
            return 0

        max_xor = 0
        mask = 0
        prefix_tree = {}
        most_significant_bit = 31

        for i in range(most_significant_bit, -1, -1):
            mask |= (1 << i)
            for num in nums:
                prefix = num & mask
                if prefix not in prefix_tree:
                    prefix_tree[prefix] = set()
                prefix_tree[prefix].add(num)

            temp_max_xor = 0
            for prefix in prefix_tree:
                for num in prefix_tree[prefix]:
                    complement = (~num & mask)
                    if complement in prefix_tree:
                        for complement_num in prefix_tree[complement]:
                            temp_max_xor = max(temp_max_xor, num ^ complement_num)

            max_xor = max(max_xor, temp_max_xor)
            if max_xor == mask:
                break

            # Remove the current bit from the prefix tree
            new_prefix_tree = {}
            for prefix in prefix_tree:
                new_prefix = prefix & ~(1 << i)
                if new_prefix not in new_prefix_tree:
                    new_prefix_tree[new_prefix] = set()
                new_prefix_tree[new_prefix].update(prefix_tree[prefix])
            prefix_tree = new_prefix_tree

        return max_xor

