#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findMaximumXOR(vector<int>& nums) {
        int max_xor = 0;
        int mask = 0;
        unordered_map<int, unordered_set<int>> prefix_tree;
        int most_significant_bit = 31;

        for (int i = most_significant_bit; i >= 0; --i) {
            mask |= (1 << i);
            prefix_tree.clear();
            for (int num : nums) {
                int prefix = num & mask;
                prefix_tree[prefix].insert(num);
            }

            int temp_max_xor = 0;
            for (auto& pair : prefix_tree) {
                for (int num : pair.second) {
                    int complement = ~num & mask;
                    if (prefix_tree.find(complement) != prefix_tree.end()) {
                        for (int complement_num : prefix_tree[complement]) {
                            temp_max_xor = max(temp_max_xor, num ^ complement_num);
                        }
                    }
                }
            }

            max_xor = max(max_xor, temp_max_xor);
            if (max_xor == mask) {
                break;
            }
        }

        return max_xor;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    Solution sol;
    int ans = sol.findMaximumXOR(nums);
    cout << ans << '\n';
    return 0;
}
